"use client"
import { todo } from 'node:test'
import { type ChangeEventHandler, useState, useEffect } from 'react'

interface TodoFormProps {
  addTodo : (todo:string) => void
}

const TodoForm = ({addTodo} : TodoFormProps) => {
  const [todo, setTodo] = useState('')
  const handleAddFormChange = (event) =>{
    setTodo(event.target.value)
  }

  const handleAddTodo = () =>{
    addTodo(todo)
    setTodo('')
  }

  return (
    <>
      <input type="text" className="border-1 rounded-2xl" onChange={handleAddFormChange} value={todo}/>
      <button onClick={handleAddTodo}>Add</button>
    </>
  )
}

interface Todo{
  id: number,
  content: string
}

interface TodosProps {
  todos: Todo[]
}

const TodoList = ({todos} : TodosProps) =>{
  return(
      <ul>
        {todos.map(todo => <li key={todo.id}>{todo.content}</li>)}
      </ul>
  )
}








interface DataItem {
  id: number
}

const useFetch = <T extends DataItem> (url: string) => {
  const [data, setData] = useState<T[]>([])

  useEffect(() => {
    const fetchData = async() => {
      const result = await fetch(url)
      const data = await result.json()
      setData(data)
    }
    fetchData()
  }, [url])
  return data
}



interface Todolist {
  id: number
  title: string
}

const Todolist = () => {
  const url = "https://fakestoreapi.com/products?limit=10"
  return useFetch<Todolist>(url)
}










const IndexPage = () => {
  const [isCheck, setIsCheck] = useState(false)
  // const [todos, setTodos] = useState([
  //   {id: 1, content: "Todo1"},
  //   {id: 2, content: "Todo2"},
  //   {id: 3, content: "Todo3"},
  //   {id: 4, content: "Todo4"},
  //   {id: 5, content: "Todo3"}
  // ])






  const apiTodos = Todolist()
  const [todos, setTodos] = useState<Todo[]>([])
  useEffect(() => {
    if (apiTodos.length > 0) {
      setTodos(
        apiTodos.map(todo =>({
          id: todo.id,
          content: todo.title
        }))
      )
    }
  }, [apiTodos])

  








  
  const addTodo = (todo:string) =>{
    setTodos([{id: todos.length + 1, content: todo}, ...todos])
  }

  const handleIsCheck = (event) =>{
    setIsCheck(event.target.checked)
  }
  return (
    <>
    <TodoForm addTodo={addTodo}/>
    <TodoList todos={todos}/>
    { isCheck && <div>Checked</div>}
    <input type="checkbox" name="" id="" onChange={handleIsCheck}/>
    </>
  )
}
export default IndexPage